@@ -0,0 +1,157 @@
+
+:root {
+  --bg-color: #050505;
+  --fg-color: #33ff00;
+  --dim-color: #004400;
+  --accent-color: #bd00ff;
+  --error-color: #ff003c;
+  --panel-bg: #0a0a0a;
+  --border-color: #33ff00;
+  --grid-line: #112211;
+  --font-mono: 'JetBrains Mono', monospace;
+  --glow: 0 0 10px rgba(51, 255, 0, 0.2);
+}
+
+* { box-sizing: border-box; }
+
+body {
+  background-color: var(--bg-color);
+  color: var(--fg-color);
+  font-family: var(--font-mono);
+  margin: 0;
+  overflow: hidden;
+  height: 100vh;
+  display: flex;
+  flex-direction: column;
+}
+
+/* CRT Scanline */
+body::after {
+  content: "";
+  position: fixed;
+  inset: 0;
+  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%), linear-gradient(90deg, rgba(255, 0, 0, 0.06), rgba(0, 255, 0, 0.02), rgba(0, 0, 255, 0.06));
+  background-size: 100% 2px, 2px 100%;
+  pointer-events: none;
+  z-index: 9999;
+}
+
+/* TUI Layout */
+.tui-screen {
+  display: flex;
+  flex-direction: column;
+  height: 100%;
+  padding: 1rem;
+  gap: 1rem;
+}
+
+.tui-header {
+  border-bottom: 2px solid var(--border-color);
+  padding-bottom: 0.5rem;
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+  text-transform: uppercase;
+  letter-spacing: 0.1em;
+}
+
+.tui-grid {
+  display: grid;
+  grid-template-columns: 300px 1fr;
+  gap: 1rem;
+  flex: 1;
+  min-height: 0;
+}
+
+.tui-panel {
+  border: 1px solid var(--border-color);
+  background: var(--panel-bg);
+  position: relative;
+  display: flex;
+  flex-direction: column;
+  box-shadow: var(--glow);
+}
+
+.tui-panel::before {
+  content: "";
+  position: absolute;
+  top: -1px; left: -1px; right: -1px; bottom: -1px;
+  border: 1px dashed var(--dim-color);
+  pointer-events: none;
+  z-index: 1;
+}
+
+.tui-panel-header {
+  background: var(--fg-color);
+  color: var(--bg-color);
+  padding: 0.25rem 0.5rem;
+  font-weight: bold;
+  text-transform: uppercase;
+  font-size: 0.8rem;
+  display: flex;
+  justify-content: space-between;
+}
+
+.tui-panel-content {
+  flex: 1;
+  overflow: auto;
+  padding: 1rem;
+}
+
+/* Controls */
+button {
+  background: transparent;
+  border: 1px solid var(--fg-color);
+  color: var(--fg-color);
+  font-family: var(--font-mono);
+  padding: 0.5rem 1rem;
+  cursor: pointer;
+  text-transform: uppercase;
+  transition: all 0.1s;
+}
+button:hover {
+  background: var(--fg-color);
+  color: var(--bg-color);
+  box-shadow: var(--glow);
+}
+button:active {
+  transform: translateY(1px);
+}
+
+input, select {
+  background: #000;
+  border: 1px solid var(--dim-color);
+  color: var(--fg-color);
+  font-family: var(--font-mono);
+  padding: 0.5rem;
+  width: 100%;
+}
+input:focus, select:focus {
+  border-color: var(--fg-color);
+  outline: none;
+  box-shadow: var(--glow);
+}
+
+/* Scrollbar */
+::-webkit-scrollbar { width: 10px; height: 10px; }
+::-webkit-scrollbar-track { background: var(--bg-color); border-left: 1px solid var(--dim-color); }
+::-webkit-scrollbar-thumb { background: var(--dim-color); border: 1px solid var(--bg-color); }
+::-webkit-scrollbar-thumb:hover { background: var(--fg-color); }
+
+/* Utility */
+.hidden { display: none !important; }
+.flex { display: flex; }
+.gap-2 { gap: 0.5rem; }
+.items-center { align-items: center; }
+.justify-between { justify-content: space-between; }
+.w-full { width: 100%; }
+.mt-4 { margin-top: 1rem; }
+.text-xs { font-size: 0.75rem; }
+.font-bold { font-weight: bold; }
+
+/* Frankenstein Stitches Decoration */
+.stitch-marker {
+  position: absolute;
+  width: 10px; height: 2px;
+  background: var(--fg-color);
+}
